    public static class NativeBridge {
        private final Activity activity;
        private final Handler handler = new Handler(Looper.getMainLooper());
        private final FusedLocationProviderClient fusedLocationClient;

        NativeBridge(Activity activity) {
            this.activity = activity;
            this.fusedLocationClient = LocationServices.getFusedLocationProviderClient(activity);
        }

        @JavascriptInterface
        public void ping(String requestJson) {
            respondOk(parseId(requestJson), "pong");
        }

        @JavascriptInterface
        public void requestCamera(String requestJson) {
            String id = parseId(requestJson);
            if (!(activity instanceof HybridWebViewActivity)) {
                respondError(id, "unsupported_host", "Host activity does not support camera request.");
                return;
            }
            HybridWebViewActivity host = (HybridWebViewActivity) activity;

            if (!host.hasAllPermissions(new String[]{Manifest.permission.CAMERA})) {
                host.requestPermissionsCompat(new String[]{Manifest.permission.CAMERA});
                respondError(id, "permission_required", "Camera permission required. Request permission and retry.");
                return;
            }

            handler.post(host::launchCameraCapture);
            respondOk(id, "camera_intent_started");
        }

        @JavascriptInterface
        public void requestLocation(String requestJson) {
            String id = parseId(requestJson);

            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED) {
                if (activity instanceof HybridWebViewActivity) {
                    ((HybridWebViewActivity) activity).requestPermissionsCompat(new String[]{Manifest.permission.ACCESS_FINE_LOCATION});
                }
                respondError(id, "permission_required", "Location permission required. Request permission and retry.");
                return;
            }

            fusedLocationClient.getLastLocation()
                    .addOnSuccessListener(activity, location -> {
                        if (location == null) {
                            respondError(id, "no_location", "No cached location available.");
                            return;
                        }
                        JSONObject payload = new JSONObject();
                        try {
                            payload.put("lat", location.getLatitude());
                            payload.put("lng", location.getLongitude());
                            payload.put("accuracy", location.getAccuracy());
                            payload.put("time", location.getTime());
                        } catch (JSONException ignored) {}
                        respondOk(id, payload);
                    })
                    .addOnFailureListener(activity, e -> respondError(id, "location_error", e.getMessage() == null ? "Location error" : e.getMessage()));
        }

        @JavascriptInterface
        public void startPayment(String requestJson) {
            String id = parseId(requestJson);
            JSONObject req = parseJson(requestJson);

            String provider = optString(req, "provider", "demo");
            JSONObject payload = new JSONObject();
            try {
                payload.put("provider", provider);
                payload.put("status", "initiated");
                payload.put("paymentIntentId", "pi_" + UUID.randomUUID());
            } catch (JSONException ignored) {}
            respondOk(id, payload);
        }

        @JavascriptInterface
        public String getDeviceInfo(String requestJson) {
            JSONObject resp = new JSONObject();
            try {
                resp.put("platform", "android");
                resp.put("sdkInt", Build.VERSION.SDK_INT);
                resp.put("manufacturer", Build.MANUFACTURER);
                resp.put("model", Build.MODEL);
                resp.put("appId", activity.getPackageName());
            } catch (JSONException ignored) {}
            return resp.toString();
        }

        @JavascriptInterface
        public void openExternalUrl(String requestJson) {
            String id = parseId(requestJson);
            JSONObject req = parseJson(requestJson);
            String url = optString(req, "url", null);
            if (url == null || url.trim().isEmpty()) {
                respondError(id, "bad_request", "Missing url");
                return;
            }
            try {
                Intent i = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                activity.startActivity(i);
                respondOk(id, "opened");
            } catch (Exception e) {
                respondError(id, "open_failed", e.getMessage() == null ? "Failed to open url" : e.getMessage());
            }
        }

        private void respondOk(String id, Object data) {
            JSONObject resp = new JSONObject();
            try {
                resp.put("id", id);
                resp.put("ok", true);
                resp.put("data", data instanceof JSONObject ? data : String.valueOf(data));
            } catch (JSONException ignored) {}
            postToWeb("nativeBridgeResponse", resp);
        }

        private void respondError(String id, String code, String message) {
            JSONObject err = new JSONObject();
            JSONObject resp = new JSONObject();
            try {
                err.put("code", code);
                err.put("message", message);
                resp.put("id", id);
                resp.put("ok", false);
                resp.put("error", err);
            } catch (JSONException ignored) {}
            postToWeb("nativeBridgeResponse", resp);
        }

        private void postToWeb(String eventName, JSONObject payload) {
            if (!(activity instanceof HybridWebViewActivity)) return;
            HybridWebViewActivity host = (HybridWebViewActivity) activity;
            host.mainHandler.post(() -> {
                if (host.webView == null) return;
                String json = payload.toString();
                String js = "(function(){try{window.dispatchEvent(new CustomEvent(" +
                        JSONObject.quote(eventName) +
                        ",{detail:" + json + "}));}catch(e){}})();";
                host.webView.evaluateJavascript(js, null);
            });
        }

        private static JSONObject parseJson(String s) {
            if (s == null) return new JSONObject();
            try { return new JSONObject(s); } catch (JSONException e) { return new JSONObject(); }
        }

        private static String parseId(String requestJson) {
            JSONObject obj = parseJson(requestJson);
            String id = optString(obj, "id", null);
            return (id == null || id.isEmpty()) ? ("req_" + UUID.randomUUID()) : id;
        }

        private static String optString(JSONObject o, String k, String def) {
            if (o == null) return def;
            String v = o.optString(k, def);
            return v == null ? def : v;
        }
    }
